  ('social-worker-moex-02031', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '學齡兒童期（6-12 歲）是語言能力發展更加精熟的時期，這時期的兒童會用較開放式的回答，並瞭解字 詞的抽象能力，此種能力的發展也能幫助孩子欣賞幽默和笑話。上述能力指的是：', '["形而上的語言覺知能力", "形而下的語言覺知能力", "隱喻的能力", "明喻的能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02032', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '身心障礙者之照顧者的身體及心理壓力負荷情形是倍受關注的議題。照顧者也需要由他人短暫協助照顧 工作，使其有紓解壓力的機會。那一項服務符合上述照顧者的需要？', '["自立生活支持服務", "喘息服務", "課後照顧", "日間及住宿式照顧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02033', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於成年前期發展的里程碑，下列敘述何者錯誤？', '["專業及生涯的發展", "生活經驗的回顧及展望", "經濟和生活的獨立", "親密關係的發展或家庭的建立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02034', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '專業人員為兒童提供服務時，需協助兒童面對可能引起複雜情緒和創傷的事件，同時，專業人員需顧及 兒童無法理解成人視為理所當然的因果概念，必須以他們能夠理解的方式和語詞解釋。請問，上述兒童 屬於皮亞傑的認知理論中的那一個階段？', '["感覺動作期", "前運思期", "具體運思期", "正式運思期"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02035', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者是生命晚期家庭之核心發展任務？', '["接受新的家庭成員", "接受孩子的獨立及祖父母的衰退", "接受成員從家庭系統移出和加入", "接受代間角色的轉移"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02036', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於自助或互助團體的討論，下列敘述何者錯誤？', '["在失智症患者之照顧者團體中，照顧者能從中得到關心和支持", "在特殊需求兒童之家長團體中，家長能從中得到有關因應孩子問題的資訊", "在身心障礙者之照顧者團體中，家庭有需要時，能夠取得物質的協助", "專業人員積極介入團體是有其必要性，必須強化團體成員的專業知能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02037', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '自我效能（self-efficacy）是那一種理論的重要觀點？', '["Freud心理動力理論", "Piaget的認知理論", "Bandura的社會學習理論", "Erikson的社會心理理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02038', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '羅伯恩萊特（Robert Enright）提出寬恕的四個階段，原則上是以下列那一種順序發展？', '["找出憤怒－決定寬恕－努力寬恕－發現與解放", "找出憤怒－努力寬恕－決定寬恕－發現與解放", "發現與解放－找出憤怒－決定寬恕－努力寬恕", "決定寬恕－找出憤怒－努力寬恕－發現與解放"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02039', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '多數父母對孩子是以權威的方式，強迫青少年子女有所承諾，例如學業成就的追求；此一事態使得青少 年未必有機會深思自己的看法或觀點。請問，上述現象符合James Marcia提及之何項青少年自我認同的 分類？', '["認定擴散（identity diffusion）", "認定喪失主動權（identity foreclosure）", "認定延期償付（identity moratorium）", "認定達成（identity achievement）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02040', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關兒童早期的溝通違常，下列敘述何者錯誤？', '["發展性的表達違常，通常是在三歲的時候會出現", "有關發展性的表達違常，有少數兒童在理解方面是有困難的", "口吃僅是急於表達所致，不是溝通違常的類型", "就性別比例而論，男童出現溝通違常的比例較女童高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
